class Entity:
    """Opaque handle to an ECS entity"""
    def __init__(self, bits: int):
        self._bits = bits

    @property
    def index(self) -> int:
        return self._bits & 0xFFFFFFFF
    @property
    def generation(self) -> int:
        return self._bits >> 32
    @property
    def is_placeholder(self) -> bool:
        return self._bits == 0xFFFFFFFFFFFFFFFF
    def to_bits(self) -> int:
        return self._bits

    def __repr__(self):
        return f"Entity({self.index}v{self.generation})"

